package com.recettealarm.app;
import android.Manifest;import android.app.*;import android.content.*;import android.database.*;import android.graphics.Typeface;import android.net.*;import android.os.*;import android.provider.Settings;import android.view.*;import android.widget.*;import java.util.*;

public class MainActivity extends Activity{DB db;LinearLayout root,list,chips;EditText search;String q="",category="Tous";String[] cats={"Tous","Tajines","Gâteaux","Plats","Desserts","Jus","Pain","Autres"};
 public void onCreate(Bundle b){super.onCreate(b);db=new DB(this);if(Build.VERSION.SDK_INT>=33)requestPermissions(new String[]{Manifest.permission.POST_NOTIFICATIONS},5);askExactAlarm();draw();}
 public void onResume(){super.onResume();if(list!=null){load();renderStats();}}
 void askExactAlarm(){try{if(Build.VERSION.SDK_INT>=31){AlarmManager am=(AlarmManager)getSystemService(ALARM_SERVICE);if(!am.canScheduleExactAlarms())startActivity(new Intent(Settings.ACTION_REQUEST_SCHEDULE_EXACT_ALARM, Uri.parse("package:"+getPackageName())));}}catch(Exception e){}}
 TextView sRecipes,sIng,sSteps;
 void draw(){root=UI.root(this);root.setPadding(UI.dp(this,16),UI.dp(this,18),UI.dp(this,16),UI.dp(this,90));
  LinearLayout top=UI.row(this);TextView menu=UI.iconBtn(this,"☰");TextView title=UI.tv(this,"Recette Alarm",30,Typeface.BOLD);TextView addTop=UI.iconBtn(this,"+");top.addView(menu);top.addView(title,new LinearLayout.LayoutParams(0,-2,1));top.addView(addTop);root.addView(top);menu.setOnClickListener(v->openMenu());addTop.setOnClickListener(v->startActivity(new Intent(this,EditRecipeActivity.class)));
  root.addView(UI.muted(this,"Bonjour Chef ! Cuisinez sans stress",14));
  search=UI.input(this,"🔎 Rechercher une recette...");root.addView(search);search.addTextChangedListener(new android.text.TextWatcher(){public void beforeTextChanged(CharSequence s,int a,int b,int c){}public void onTextChanged(CharSequence s,int a,int b,int c){q=s.toString().toLowerCase();load();}public void afterTextChanged(android.text.Editable e){}});
  LinearLayout catHead=UI.row(this);catHead.addView(UI.tv(this,"Catégories",21,Typeface.BOLD),new LinearLayout.LayoutParams(0,-2,1));TextView all=UI.tv(this,"Voir tout",15,Typeface.BOLD);all.setTextColor(UI.terracotta);catHead.addView(all);root.addView(catHead);all.setOnClickListener(v->{category="Tous";renderChips();load();});
  HorizontalScrollView hsv=new HorizontalScrollView(this);hsv.setHorizontalScrollBarEnabled(false);chips=new LinearLayout(this);chips.setOrientation(LinearLayout.HORIZONTAL);hsv.addView(chips);root.addView(hsv);renderChips();
  LinearLayout stats=UI.row(this);sRecipes=stat("🍽",0,"recettes");sIng=stat("🥕",0,"ingrédients");sSteps=stat("🔥",0,"étapes");stats.addView(sRecipes,new LinearLayout.LayoutParams(0,-2,1));stats.addView(sIng,new LinearLayout.LayoutParams(0,-2,1));stats.addView(sSteps,new LinearLayout.LayoutParams(0,-2,1));root.addView(stats);renderStats();
  root.addView(UI.tv(this,"Vos Recettes",22,Typeface.BOLD));list=new LinearLayout(this);list.setOrientation(LinearLayout.VERTICAL);root.addView(list);load();
  Button fab=UI.btn(this,"+ Nouvelle Recette");fab.setTextSize(16);fab.setOnClickListener(v->startActivity(new Intent(this,EditRecipeActivity.class)));root.addView(fab);
 }
 TextView stat(String icon,int n,String label){TextView v=UI.center(this,icon+"  "+n+"\n"+label,13,Typeface.BOLD);v.setBackground(UI.stroke(this,0xffffffff,UI.dp(this,22),0xffeadfd4));v.setPadding(UI.dp(this,8),UI.dp(this,10),UI.dp(this,8),UI.dp(this,10));return v;}
 void renderStats(){if(sRecipes!=null){sRecipes.setText("🍽  "+db.count("recipes")+"\nrecettes");sIng.setText("🥕  "+db.count("ingredients")+"\ningrédients");sSteps.setText("🔥  "+db.count("steps")+"\nétapes");}}
 void renderChips(){chips.removeAllViews();for(String c:cats){TextView chip=UI.chip(this,(c.equals("Tous")?"▦  ":"")+c,c.equals(category));chips.addView(chip);chip.setOnClickListener(v->{String t=((TextView)v).getText().toString().replace("▦  ","");category=t;renderChips();load();});}}
 void load(){list.removeAllViews();Cursor c=db.recipesByCategory(category);ArrayList<Long> ids=new ArrayList<>();ArrayList<String[]> data=new ArrayList<>();ArrayList<Integer> ints=new ArrayList<>();while(c.moveToNext()){long id=c.getLong(c.getColumnIndexOrThrow("id"));String t=s(c,"title"),cat=s(c,"category"),img=s(c,"image"),water=s(c,"water_liters");int time=c.getInt(c.getColumnIndexOrThrow("time")),serv=c.getInt(c.getColumnIndexOrThrow("servings")),rating=c.getInt(c.getColumnIndexOrThrow("rating"));if(q.length()>0&&!t.toLowerCase().contains(q)&&!cat.toLowerCase().contains(q))continue;ids.add(id);data.add(new String[]{t,cat,img,water});ints.add(time);ints.add(serv);ints.add(rating);}c.close();
  for(int i=0;i<ids.size();i+=2){LinearLayout row=UI.row(this);row.setGravity(Gravity.TOP);for(int j=0;j<2;j++){int k=i+j;LinearLayout card=k<ids.size()?recipeCard(ids.get(k),data.get(k),ints.get(k*3),ints.get(k*3+1),ints.get(k*3+2)):new LinearLayout(this);LinearLayout.LayoutParams lp=new LinearLayout.LayoutParams(0,-2,1);lp.setMargins(UI.dp(this,j==0?0:8),0,UI.dp(this,j==0?8:0),UI.dp(this,18));row.addView(card,lp);}list.addView(row);}if(ids.size()==0)list.addView(UI.smallCard(this,"Aucune recette trouvée. Clique sur + pour créer une recette avec photo, vidéos, ingrédients et étapes."));}
 LinearLayout recipeCard(long id,String[] d,int time,int serv,int rating){LinearLayout card=new LinearLayout(this);card.setOrientation(LinearLayout.VERTICAL);card.setBackground(UI.stroke(this,0xffffffff,UI.dp(this,30),0x00ffffff));card.setPadding(0,0,0,UI.dp(this,12));ImageView img=UI.image(this,d[2],155);img.setBackground(UI.bg(0xfff2e5d6,UI.dp(this,28)));card.addView(img);TextView cat=UI.tv(this,d[1],12,Typeface.BOLD);cat.setTextColor(UI.terracotta);cat.setPadding(UI.dp(this,12),0,0,0);card.addView(cat);TextView title=UI.tv(this,shorten(d[0]),19,Typeface.BOLD);title.setPadding(UI.dp(this,12),0,UI.dp(this,10),0);card.addView(title);LinearLayout meta=UI.row(this);TextView m=UI.muted(this,"👥 "+serv+" pers.   ⏱ "+time+" min",13);meta.addView(m,new LinearLayout.LayoutParams(0,-2,1));TextView heart=UI.center(this,"♡",28,Typeface.BOLD);heart.setTextColor(0xffd01818);meta.addView(heart);meta.setPadding(UI.dp(this,12),0,UI.dp(this,10),0);card.addView(meta);TextView stars=UI.tv(this,UI.stars(rating),14,Typeface.BOLD);stars.setTextColor(UI.gold);stars.setPadding(UI.dp(this,12),0,0,0);card.addView(stars);card.setOnClickListener(v->startActivity(new Intent(this,DetailActivity.class).putExtra("id",id)));return card;}
 String shorten(String s){return s==null?"Recette":s.length()>20?s.substring(0,20)+"...":s;}
 void openMenu(){final String[] items={"🍽 Toutes les recettes","❤️ Favoris","🛒 Liste de courses","📐 Convertisseur mesures","⏱ Minuteurs","⚙️ Paramètres","🛠 Admin","➕ Nouvelle recette"};new AlertDialog.Builder(this).setTitle("Menu Recette Alarm").setItems(items,(d,which)->{if(which==0){category="Tous";renderChips();load();}else if(which==1){startActivity(new Intent(this,FavoritesActivity.class));}else if(which==2){startActivity(new Intent(this,ShoppingActivity.class));}else if(which==3){showText("Convertisseur",db.conversions());}else if(which==4){startActivity(new Intent(this,CookingActivity.class));}else if(which==5){startActivity(new Intent(this,SettingsActivity.class));}else if(which==6){startActivity(new Intent(this,AdminActivity.class));}else startActivity(new Intent(this,EditRecipeActivity.class));}).show();}
 void showText(String title,String msg){new AlertDialog.Builder(this).setTitle(title).setMessage(msg).setPositiveButton("OK",null).show();}
 String s(Cursor c,String col){try{String x=c.getString(c.getColumnIndexOrThrow(col));return x==null?"":x;}catch(Exception e){return "";}}
}
